    private val Xxh32Hex = Xxh32HexChunks.mkString
    private val Xxh64Hex = Xxh64HexChunks.mkString

    def xxh32(length: Int, seeded: Boolean): Int =
        java.lang.Integer.parseUnsignedInt(slice(Xxh32Hex, 8, length, seeded), 16)

    def xxh64(length: Int, seeded: Boolean): Long =
        java.lang.Long.parseUnsignedLong(slice(Xxh64Hex, 16, length, seeded), 16)

    private def slice(hex: String, width: Int, length: Int, seeded: Boolean): String = {
        val index = length * 2 + (if (seeded) 1 else 0)
        val start = index * width
        hex.substring(start, start + width)
    }
